    public interface SessionStore {
        void save(AuthenticatedSession session);

        Optional<AuthenticatedSession> findBySessionId(String sessionId);

        Optional<AuthenticatedSession> findByNameId(String nameId);

        void invalidate(String sessionId);
    }

    public static final class InMemorySessionStore implements SessionStore {
        private final Map<String, AuthenticatedSession> bySessionId = new ConcurrentHashMap<>();
        private final Map<String, String> sessionIdByNameId = new ConcurrentHashMap<>();

        @Override
        public void save(AuthenticatedSession session) {
            Objects.requireNonNull(session, "session");
            bySessionId.put(session.getSessionId(), session);
            if (session.getNameId() != null) {
                sessionIdByNameId.put(session.getNameId(), session.getSessionId());
            }
        }

        @Override
        public Optional<AuthenticatedSession> findBySessionId(String sessionId) {
            if (sessionId == null) return Optional.empty();
            return Optional.ofNullable(bySessionId.get(sessionId));
        }

        @Override
        public Optional<AuthenticatedSession> findByNameId(String nameId) {
            if (nameId == null) return Optional.empty();
            String sid = sessionIdByNameId.get(nameId);
            if (sid == null) return Optional.empty();
            return findBySessionId(sid);
        }

        @Override
        public void invalidate(String sessionId) {
            if (sessionId == null) return;
            AuthenticatedSession removed = bySessionId.remove(sessionId);
            if (removed != null && removed.getNameId() != null) {
                sessionIdByNameId.remove(removed.getNameId(), sessionId);
            }
        }
    }

